{
var seed = GetInt(parameters, "seed", context.Seed);
    var shieldType = GetChoice(parameters, "shieldType", "round");
    var size = GetFloat(parameters, "size", 0.6f);
    var baseColor = GetColor(parameters, "baseColor", Color.FromRgb(180, 50, 50));
    var borderColor = GetColor(parameters, "borderColor", Color.FromRgb(200, 170, 100));
    var accentColor = GetColor(parameters, "accentColor", Color.FromRgb(220, 200, 150));
    var pattern = GetChoice(parameters, "pattern", "none");

    var tileSize = context.TileSize;
    var buffer = new PixelBuffer(tileSize, tileSize);

    var bR = baseColor.R / 255f; var bG = baseColor.G / 255f; var bB = baseColor.B / 255f;
    var oR = borderColor.R / 255f; var oG = borderColor.G / 255f; var oB = borderColor.B / 255f;
    var aR = accentColor.R / 255f; var aG = accentColor.G / 255f; var aB = accentColor.B / 255f;

    var halfSize = tileSize * 0.5f;
    var radius = halfSize * size;

    buffer.ParallelForEachPixel((x, y) =>
    {
        var px = (x + 0.5f - halfSize) / radius;
        var py = (y + 0.5f - halfSize) / radius;

        // Shield silhouette based on type
        var dist = shieldType switch
        {
            "square" => MathF.Max(MathF.Abs(px), MathF.Abs(py)),
            "kite" => KiteShieldSDF(px, py),
            "tower" => TowerShieldSDF(px, py),
            _ => MathF.Sqrt(px * px + py * py) // round
        };

        // Adding slight bottom point to kite/tower
        var baseRadius = shieldType switch
        {
            "tower" => 1.2f,
            _ => 1f
        };

        var alpha = 1f - SmoothStep(baseRadius * 0.85f, baseRadius, dist);
        if (alpha <= 0.01f)
        {
            buffer.SetPixel(x, y, 0, 0, 0, 0);
            return;
        }

        // Border zone
        var borderWidth = 0.12f;
        var isBorder = dist > baseRadius * (0.85f - borderWidth) && dist < baseRadius * 0.85f;

        // Interior zone for patterns
        var interiorDist = dist / (baseRadius * 0.75f);

        // Determine color
        float fr, fg, fb;

        if (isBorder)
        {
            fr = oR; fg = oG; fb = oB;
        }
        else if (dist < baseRadius * 0.75f)
        {
            // Interior: apply pattern
            var applyPattern = pattern switch
            {
                "cross" => MathF.Abs(px) < 0.2f || MathF.Abs(py) < 0.2f,
                "stripes" => ((int)((py + 1f) * 4f) & 1) == 0,
                "diamond" => (MathF.Abs(px) + MathF.Abs(py) * 0.7f) < 0.5f,
                "beast" => SimulateBeastHead(px, py, seed),
                _ => false
            };

            // Lighting: dome shading
            var light = (1f - px) * 0.2f + (1f - py) * 0.2f + 0.4f;
            light = Math.Clamp(light, 0f, 1f);
            var lightColor = 0.7f + light * 0.3f;

            if (applyPattern)
            {
                fr = aR * lightColor; fg = aG * lightColor; fb = aB * lightColor;
            }
            else
            {
                fr = bR * lightColor; fg = bG * lightColor; fb = bB * lightColor;
            }

            // Add subtle rivet dots
            if (isBorder)
            {
                var rivetX = ((int)(px * 8 + 1000) % 3) == 0;
                var rivetY = ((int)(py * 8 + 1000) % 3) == 0;
                if (rivetX && rivetY) { fr = oR * 1.2f; fg = oG * 1.2f; fb = oB * 1.2f; }
            }
        }
        else
        {
            // Gradient between border and center
            var t = (dist - baseRadius * 0.75f) / (baseRadius * 0.1f);
            var innerColor = (pattern != "none") ? aR : bR;
            fr = Lerp(bR, oR, t); fg = Lerp(bG, oG, t); fb = Lerp(bB, oB, t);
        }

        // Edge highlight for 3D effect
        var edgeHL = (1f - dist / baseRadius) * 0.3f;
        fr += edgeHL; fg += edgeHL; fb += edgeHL;

        buffer.SetPixel(x, y,
            Math.Clamp(fr, 0f, 1f),
            Math.Clamp(fg, 0f, 1f),
            Math.Clamp(fb, 0f, 1f), alpha);
    });

    return buffer;

private static float KiteShieldSDF(float px, float py)
{
    // Kite shield: rounded top, pointed bottom
    var topPart = MathF.Sqrt(px * px + py * py * 1.5f);
    var bottomPart = MathF.Abs(px) + (py + 0.3f) * 1.2f;
    return py < 0f ? topPart : bottomPart;
}

private static float TowerShieldSDF(float px, float py)
{
    // tall rectangle with slightly rounded top
    var rx = MathF.Abs(px);
    var ry = MathF.Abs(py);
    if (ry > rx)
    {
        // top corners rounded
        if (py < 0f) return MathF.Sqrt(rx * rx + ry * ry) - 1f;
        return ry - 1.2f;
    }
    return rx - 0.9f;
}

private static bool SimulateBeastHead(float px, float py, int seed)
{
    // Simple beast head silhouette using primitive shapes
    // Head circle
    var headDist = MathF.Sqrt(px * px + (py + 0.1f) * (py + 0.1f));
    if (headDist > 0.5f) return false;

    // Eyes: two small dots
    var leftEye = MathF.Sqrt((px + 0.2f) * (px + 0.2f) + (py - 0.1f) * (py - 0.1f));
    var rightEye = MathF.Sqrt((px - 0.2f) * (px - 0.2f) + (py - 0.1f) * (py - 0.1f));
    if (leftEye < 0.08f || rightEye < 0.08f) return true;

    // Mouth: horizontal line
    if (MathF.Abs(py - 0.25f) < 0.04f && MathF.Abs(px) < 0.25f) return true;

    // Horns
    var leftHorn = MathF.Sqrt((px + 0.3f) * (px + 0.3f) + (py + 0.5f) * (py + 0.5f));
    var rightHorn = MathF.Sqrt((px - 0.3f) * (px - 0.3f) + (py + 0.5f) * (py + 0.5f));
    if (leftHorn < 0.15f || rightHorn < 0.15f) return true;

    return false;
    }
}
